export const creatorBySlug = Object.fromEntries(creators.map((c) => [c.slug, c]))

export function suggestionsFor(slug, count = 4) {
  return creators
    .filter((c) => c.slug !== slug)
    .slice(0, count)
    .map((c) => ({ name: c.name, handle: c.handle, image: c.avatarImage }))
}
